import{bV as a,aL as n,u as i,G as e}from"./chunks/framework.BfzMay2U.js";const k=JSON.parse('{"title":"手写 HashMap（设计哈希表）","description":"从零实现一个哈希表，深入理解哈希函数、冲突解决与扩容机制","frontmatter":{"title":"手写 HashMap（设计哈希表）","description":"从零实现一个哈希表，深入理解哈希函数、冲突解决与扩容机制","date":"2026-06-17T09:00:00.000Z","categories":["Algorithm"],"tags":["hash-map","design","data-structure"],"sidebarSort":47},"headers":[],"relativePath":"algo/design-hashmap.md","filePath":"algo/design-hashmap.md"}'),p={name:"algo/design-hashmap.md"};function l(t,s,h,r,d,c){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="手写-hashmap-设计哈希表" tabindex="-1">手写 HashMap（设计哈希表） <a class="header-anchor" href="#手写-hashmap-设计哈希表" aria-label="Permalink to &quot;手写 HashMap（设计哈希表）&quot;">​</a></h1><p>面试官：&quot;你天天用 <code>Map</code>、<code>dict</code>、<code>HashMap</code>，能不能从零手写一个？&quot;</p><p>听起来简单对吧？不就是 key-value 存取嘛。但一写起来你会发现——问题全来了：<strong>哈希冲突怎么办？什么时候扩容？扩容的时候旧数据怎么迁移？</strong> 这些问题搞不清楚，面试直接 GG。</p><p>今天我们就来拆解 HashMap 的核心原理，然后用 TypeScript 从零实现一个支持 O(1) 增删查的哈希表 💪</p><h2 id="为什么需要-hashmap" tabindex="-1">为什么需要 HashMap？ <a class="header-anchor" href="#为什么需要-hashmap" aria-label="Permalink to &quot;为什么需要 HashMap？&quot;">​</a></h2><p>假设你有一个用户列表，需要根据用户 ID 快速查用户信息。最朴素的想法是用数组遍历：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>users = [{id: 1, name: &quot;Alice&quot;}, {id: 2, name: &quot;Bob&quot;}, ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>查 id=999 的用户 → 遍历数组 → O(n) 😭</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>1 万个用户还行，100 万个用户就要命了。如果能让 <strong>查找速度变成 O(1)</strong>，该多好？</p><p>这就是 HashMap 诞生的原因——它通过一个<strong>哈希函数</strong>把 key 转换成数组下标，直接跳到对应位置取数据，不遍历。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key &quot;user:999&quot; → hash(&quot;user:999&quot;) → 37 → buckets[37] → 直接拿到 value</span></span>
<span class="line"><span></span></span>
<span class="line"><span>时间复杂度：O(1) ✅</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="_1-哈希函数" tabindex="-1">1. 哈希函数 <a class="header-anchor" href="#_1-哈希函数" aria-label="Permalink to &quot;1. 哈希函数&quot;">​</a></h3><p>哈希函数的核心任务是：<strong>把任意类型的 key 映射成一个非负整数（数组下标）</strong>。</p><p>一个好的哈希函数需要：</p><ul><li><strong>确定性</strong>：同一个 key 每次哈希的结果必须一样</li><li><strong>均匀性</strong>：不同 key 尽量均匀分布在各个位置，减少冲突</li><li><strong>高效性</strong>：计算速度快，O(1) 或接近 O(1)</li></ul><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 一个简单的字符串哈希函数（DJB2 算法）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> hash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">capacity</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5381</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> key.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // hash * 33 + charCode，经典的 DJB2 哈希</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ((hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> key.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">charCodeAt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(i)) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;&gt;&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hash </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> capacity;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><blockquote><p>为什么要 <code>&gt;&gt;&gt; 0</code>？JavaScript 的位运算会把数字转成 32 位有符号整数，<code>&gt;&gt;&gt; 0</code> 强制转成无符号，保证结果非负。</p></blockquote><h3 id="_2-哈希冲突" tabindex="-1">2. 哈希冲突 <a class="header-anchor" href="#_2-哈希冲突" aria-label="Permalink to &quot;2. 哈希冲突&quot;">​</a></h3><p>不管哈希函数设计得多好，只要 key 的数量大于桶的数量（或者 key 空间无穷大），<strong>冲突不可避免</strong>。比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hash(&quot;cat&quot;) % 8 = 3</span></span>
<span class="line"><span>hash(&quot;dog&quot;) % 8 = 3   ← 冲突了！两个 key 落到同一个桶</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>怎么解决？主流方案有两种：</p><h4 id="方案一-链地址法-chaining" tabindex="-1">方案一：链地址法（Chaining） <a class="header-anchor" href="#方案一-链地址法-chaining" aria-label="Permalink to &quot;方案一：链地址法（Chaining）&quot;">​</a></h4><p>每个桶不直接存数据，而是存一个<strong>链表</strong>（或数组）。冲突的元素追加到链表末尾。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>buckets[0] → null</span></span>
<span class="line"><span>buckets[1] → [key1, val1] → null</span></span>
<span class="line"><span>buckets[2] → null</span></span>
<span class="line"><span>buckets[3] → [cat, &quot;🐱&quot;] → [dog, &quot;🐕&quot;] → null  ← 冲突元素串在链表里</span></span>
<span class="line"><span>buckets[4] → null</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ul><li>✅ 实现简单，负载因子可以大于 1</li><li>❌ 链表太长时退化成 O(n)</li><li>📌 Java 的 <code>HashMap</code>、JavaScript 的 V8 引擎用的就是这种</li></ul><h4 id="方案二-开放寻址法-open-addressing" tabindex="-1">方案二：开放寻址法（Open Addressing） <a class="header-anchor" href="#方案二-开放寻址法-open-addressing" aria-label="Permalink to &quot;方案二：开放寻址法（Open Addressing）&quot;">​</a></h4><p>所有元素都直接存在桶数组里。冲突时按照某种探测策略找下一个空位：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>插入 &quot;cat&quot; → hash = 3 → buckets[3] 为空 → 放进去 ✅</span></span>
<span class="line"><span>插入 &quot;dog&quot; → hash = 3 → buckets[3] 已占用 → 探测下一个</span></span>
<span class="line"><span>                      → buckets[4] 为空 → 放进去 ✅</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>常见的探测策略：</p><ul><li><p><strong>线性探测</strong>：冲突了就往后找（+1, +2, +3...），简单但容易&quot;聚集&quot;</p></li><li><p><strong>二次探测</strong>：按平方步长找（+1, +4, +9...），缓解聚集</p></li><li><p><strong>双重哈希</strong>：用第二个哈希函数算步长，分布最均匀</p></li><li><p>✅ 数据存在连续内存，缓存友好</p></li><li><p>❌ 负载因子必须控制在 0.7 以下，否则性能急剧下降</p></li><li><p>📌 Python 的 <code>dict</code>、Go 的 <code>map</code> 用的是开放寻址的变体</p></li></ul><h3 id="_3-负载因子与扩容" tabindex="-1">3. 负载因子与扩容 <a class="header-anchor" href="#_3-负载因子与扩容" aria-label="Permalink to &quot;3. 负载因子与扩容&quot;">​</a></h3><p><strong>负载因子（Load Factor）</strong> = 已存元素数 / 桶的数量</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>capacity = 8, size = 6</span></span>
<span class="line"><span>load factor = 6 / 8 = 0.75</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>负载因子越大，冲突概率越高，查找越慢。当负载因子超过阈值（通常 0.75），就需要<strong>扩容（resize）</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>扩容前：capacity = 8, size = 6, loadFactor = 0.75</span></span>
<span class="line"><span>触发扩容！</span></span>
<span class="line"><span>扩容后：capacity = 16, 重新哈希所有元素到新桶数组</span></span>
<span class="line"><span>新 loadFactor = 6 / 16 = 0.375 ✅ 冲突率大幅下降</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>容量为什么要翻倍？因为翻倍后每个元素的新位置 = 要么在原位，要么在原位 + 旧容量，方便计算。</p><h2 id="代码实现" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现" aria-label="Permalink to &quot;代码实现&quot;">​</a></h2><p>接下来我们用 TypeScript 手写一个完整的 HashMap。采用<strong>链地址法</strong>，支持：</p><ul><li><code>put(key, value)</code> —— 插入/更新</li><li><code>get(key)</code> —— 查找</li><li><code>delete(key)</code> —— 删除</li><li>自动扩容</li></ul>`,39)])])}const u=a(p,[["render",l]]);export{k as __pageData,u as default};
